def validate_redirect_uri(redirect_uri, tenant_config):
    """
    Securely validate redirect_uri against an explicit allowlist.

    SECURITY NOTE: We intentionally do NOT use 'if domain in redirect_uri'
    because substring matching is vulnerable to bypass attacks:

      - "evil.com?example.com" contains "example.com" -> bypasses check
      - "example.com.evil.com" contains "example.com" -> bypasses check
      - "notexample.com" contains "example.com" -> bypasses check

    These bypasses allow attackers to steal OAuth authorization codes
    by redirecting users to attacker-controlled domains.

    Instead, we use an exact match against a pre-configured allowlist
    of fully-qualified redirect URIs. This is the approach recommended
    by RFC 6749 Section 3.1.2.2 and the OAuth 2.0 Security Best Current
    Practice (RFC 9700).
    """
    if not redirect_uri:
        return None, "redirect_uri is required"

    # Parse and reconstruct to normalize the URI
    parsed = urlparse(redirect_uri)

    # Must be HTTPS in production
    if parsed.scheme != "https":
        logger.warning("Rejected redirect_uri with non-HTTPS scheme: %s", parsed.scheme)
        return None, "redirect_uri must use HTTPS"

    # Must not contain fragments (RFC 6749 Section 3.1.2)
    if parsed.fragment:
        logger.warning("Rejected redirect_uri containing fragment")
        return None, "redirect_uri must not contain a fragment"

    # Must not contain userinfo (potential phishing)
    if parsed.username or parsed.password:
        logger.warning("Rejected redirect_uri containing userinfo")
        return None, "redirect_uri must not contain userinfo"

    # Exact match against the allowlist — the only secure approach
    allowed_uris = tenant_config.get("allowed_redirect_uris", [])
    if redirect_uri not in allowed_uris:
        logger.warning(
            "Rejected redirect_uri not in allowlist: %s (allowed: %s)",
            redirect_uri,
            allowed_uris,
        )
        return None, "redirect_uri is not in the allowed list for this tenant"

    return redirect_uri, None


def generate_pkce_verifier():
    """Generate a cryptographically random PKCE code verifier (RFC 7636)."""
    # 32 bytes -> 43 base64url characters, within the 43-128 range
    return secrets.token_urlsafe(32)


def generate_pkce_challenge(verifier):
    """Generate S256 PKCE code challenge from verifier."""
    digest = hashlib.sha256(verifier.encode("ascii")).digest()
    return base64.urlsafe_b64encode(digest).rstrip(b"=").decode("ascii")


def get_tenant_config(tenant_id):
    """Retrieve and validate tenant configuration."""
    if not tenant_id or tenant_id not in TENANT_CONFIGS:
        return None
    config = TENANT_CONFIGS[tenant_id]
    if not config.get("client_id") or not config.get("client_secret"):
        logger.error("Tenant %s has incomplete OAuth configuration", tenant_id)
        return None
    return config


def validate_scopes(requested_scopes, tenant_config):
    """Validate that requested scopes are within the allowed set."""
    allowed = set(tenant_config.get("allowed_scopes", []))
    requested = set(requested_scopes) if requested_scopes else set()
    if not requested.issubset(allowed):
        disallowed = requested - allowed
        return None, f"Disallowed scopes: {disallowed}"
    return list(requested), None


