    # Validate requested scopes
    requested_scopes = request.args.getlist("scope") or tenant_config["allowed_scopes"]
    scopes, error = validate_scopes(requested_scopes, tenant_config)
    if error:
        abort(400, description=error)

    # Generate cryptographic state parameter to prevent CSRF
    state = secrets.token_urlsafe(32)

    # Generate PKCE parameters (RFC 7636) to prevent authorization code interception
    code_verifier = generate_pkce_verifier()
