# --- Demonstration of why substring matching is dangerous ---
def demonstrate_redirect_uri_bypass():
    """
    This function illustrates why 'if domain in redirect_uri' is insecure.
    It is NOT used in the application — it exists only for educational purposes.
    """
    domain = "example.com"

    malicious_uris = [
        # Attacker's domain with legitimate domain as subdomain prefix
        "https://example.com.evil.com/callback",
        # Attacker's domain with legitimate domain in query string
        "https://evil.com/callback?ref=example.com",
        # Attacker's domain with legitimate domain in path
        "https://evil.com/example.com/callback",
        # Attacker's domain with legitimate domain in fragment
        "https://evil.com/callback#example.com",
        # Attacker's domain with legitimate domain as username
        "https://example.com@evil.com/callback",
    ]

    print("=== Demonstrating 'domain in redirect_uri' bypass ===")
    print(f"Configured domain: {domain}\n")

    for uri in malicious_uris:
        # INSECURE: substring check — all of these pass!
        insecure_result = domain in uri

        # SECURE: exact allowlist match
        allowlist = [
            "https://example.com/oauth/callback",
            "https://app.example.com/oauth/callback",
        ]
        secure_result = uri in allowlist

        print(f"URI: {uri}")
        print(f"  Substring check (INSECURE): {'PASS' if insecure_result else 'BLOCK'}")
        print(f"  Allowlist check (SECURE):   {'PASS' if secure_result else 'BLOCK'}")
